fixed_code:
enum Color { Red, Green, Blue }

trait ColorExt {
    fn get_name(&self) -> String;
}

impl ColorExt for Color {
    fn get_name(&self) -> String {
        match *self {
            Color::Red => "Red".to_string(),
            Color::Green => "Green".to_string(),
            Color::Blue => "Blue".to_string(),
        }
    }
}

